def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    min_idx, max_idx = 1, n - 2

    if n % 2 == 0:
        mean = sum(nums[min_idx:max_idx]) / (n - 2)
    else:
        mean = (sum(nums[min_idx:max_idx]) + nums[(n - 1) // 2]) / n

    return mean
